const Calculadora={_resultado:0,get resultado(){return this._resultado},somar(t,s=0){const r=t+s;return this._resultado+=r,this},potencia(t,s){const r=t**s;return this._resultado+=r,this},zerar(){return this._resultado=0,this},log(){console.log(this._resultado)}};
console.log(Calculadora.somar(5).potencia(2,8).resultado),Calculadora.zerar().somar(2,3).somar(3).log();